INSERT INTO directives (id, org, deleted, version, updated_at, data) VALUES ('dir_mqy5rhzm_13', 'omega-1', 0, 1, '2026-06-16T19:04:41.938Z', '{"id":"dir_mqy5rhzm_13","ref":"O1-SO-001","org":"omega-1","clearance":"CL3","title":"Standing Orders — Field Conduct","body":"All Omega-1 operatives maintain weapons-tight posture until a containment breach is confirmed by the deployment lead. After-action reports are filed within twelve hours of return to site. Deviation is recorded as a strike.","issuedBy":"O1-1","status":"active","createdAt":"2026-06-16T19:04:41.938Z","updatedAt":"2026-06-16T19:04:41.938Z","version":1,"deleted":false,"deletedAt":null}');
INSERT INTO directives (id, org, deleted, version, updated_at, data) VALUES ('dir_mqy5rhzm_14', 'ethics-committee', 0, 1, '2026-06-08T19:04:41.938Z', '{"id":"dir_mqy5rhzm_14","ref":"EC-DIR-014","org":"ethics-committee","clearance":"CL4-J","title":"Containment Ethics Review Protocol","body":"Any containment procedure resulting in Class-D attrition above threshold is referred to the Committee for review within five working days. Reviewing members recuse themselves from cases involving their own prior rulings.","issuedBy":"EC-1","status":"active","createdAt":"2026-06-08T19:04:41.938Z","updatedAt":"2026-06-08T19:04:41.938Z","version":1,"deleted":false,"deletedAt":null}');
INSERT INTO directives (id, org, deleted, version, updated_at, data) VALUES ('dir_mqy5rhzm_15', 'command', 0, 1, '2026-05-29T19:04:41.938Z', '{"id":"dir_mqy5rhzm_15","ref":"CMD-DIR-001","org":"command","clearance":"CL3","title":"CAIRO Access & Clearance Policy","body":"Access to CAIRO is granted on a need-to-know basis. Clearance is assigned by Command and may not be self-amended. Registrations require CL5 approval before activation. Credentials are personal and non-transferable.","issuedBy":"CMD-1","status":"active","createdAt":"2026-05-29T19:04:41.938Z","updatedAt":"2026-05-29T19:04:41.938Z","version":1,"deleted":false,"deletedAt":null}');
INSERT INTO subjects (id, org, deleted, version, updated_at, data) VALUES ('sub_mqy5rhzm_16', 'omega-1', 0, 1, '2026-06-02T19:04:41.938Z', '{"id":"sub_mqy5rhzm_16","ref":"POI-2207","alias":"Cassette","realName":"[UNIDENTIFIED]","kind":"poi","org":"omega-1","threat":"moderate","clearance":"CL3","status":"active","summary":"Suspected courier moving anomalous media between two unaffiliated groups of interest. Non-hostile to date; observe and map contacts.","lastKnownLocation":"Metro corridor, Sector 12","logs":[{"id":"log_mqy5rhzm_17","ts":"2026-06-02T19:04:41.938Z","by":"O1-1","type":"intel","text":"Watch opened following recovered handoff footage."},{"id":"log_mqy5rhzm_18","ts":"2026-06-17T19:04:41.938Z","by":"O1-7","type":"sighting","text":"Observed at transit hub; met one unidentified contact for under two minutes."},{"id":"log_mqy5rhzm_19","ts":"2026-06-25T19:04:41.938Z","by":"O1-1","type":"note","text":"Pattern suggests weekly cadence. Maintain passive watch."}],"createdBy":"O1-1","createdAt":"2026-06-02T19:04:41.938Z","updatedAt":"2026-06-02T19:04:41.938Z","version":1,"deleted":false,"deletedAt":null}');
INSERT INTO subjects (id, org, deleted, version, updated_at, data) VALUES ('sub_mqy5rhzm_1a', 'omega-1', 0, 1, '2026-05-19T19:04:41.938Z', '{"id":"sub_mqy5rhzm_1a","ref":"TGT-118","alias":"Hollow King","realName":"[UNIDENTIFIED]","kind":"target","org":"omega-1","threat":"critical","clearance":"CL4-S","status":"located","summary":"High-priority acquisition target linked to two containment breaches. Approach only with task-force authorisation.","lastKnownLocation":"Disused rail depot (under confirmation)","logs":[{"id":"log_mqy5rhzm_1b","ts":"2026-05-19T19:04:41.938Z","by":"O1-1","type":"intel","text":"Designated acquisition target by Omega-1 command."},{"id":"log_mqy5rhzm_1c","ts":"2026-06-19T19:04:41.938Z","by":"O1-1","type":"status","text":"Location narrowed to depot district; surveillance assets repositioned."},{"id":"log_mqy5rhzm_1d","ts":"2026-06-27T19:04:41.938Z","by":"O1-7","type":"sighting","text":"Probable visual confirmation pending corroboration."}],"createdBy":"O1-1","createdAt":"2026-05-19T19:04:41.938Z","updatedAt":"2026-05-19T19:04:41.938Z","version":1,"deleted":false,"deletedAt":null}');
