INSERT INTO cases (id, deleted, version, updated_at, data) VALUES ('case_mqy5rhzn_1k', 0, 1, '2026-05-29T19:04:41.939Z', '{"id":"case_mqy5rhzn_1k","ref":"EC-CASE-26-002","title":"Operative Disciplinary Tribunal — Probate","kind":"tribunal","clearance":"CL3","status":"ruled","summary":"Referral from Omega-1 command following a third active strike against the named operative. The Committee convened to determine whether the pattern warranted escalation.","respondentId":"usr_mqy5rhrq_w","respondentName":null,"panelIds":["usr_mqy5rhtp_y","usr_mqy5rhvo_10"],"linkedSubjectIds":[],"summons":[{"id":"sum_mqy5rhzn_1l","ts":"2026-05-31T19:04:41.939Z","by":"EC-1","targetId":"usr_mqy5rhrq_w","targetName":null,"reason":"Appear before the Committee to answer for repeated conduct infractions."}],"entries":[{"id":"ent_mqy5rhzn_1m","ts":"2026-05-29T19:04:41.939Z","by":"EC-1","type":"filing","text":"Case opened on referral from Omega-1 command."},{"id":"ent_mqy5rhzn_1n","ts":"2026-05-31T19:04:41.939Z","by":"EC-3","type":"testimony","text":"Respondent testimony heard; mitigating circumstances noted for the record."},{"id":"ent_mqy5rhzn_1o","ts":"2026-06-02T19:04:41.939Z","by":"EC-1","type":"ruling","text":"Panel ruling entered and served."}],"ruling":{"ts":"2026-06-02T19:04:41.939Z","by":"EC-1","finding":"upheld","rationale":"A pattern of infractions was established on the record and not adequately rebutted.","measures":"Final written warning; probation extended ninety days; reassignment review deferred pending conduct."},"createdBy":"EC-1","createdAt":"2026-05-29T19:04:41.939Z","updatedAt":"2026-05-29T19:04:41.939Z","version":1,"deleted":false,"deletedAt":null}');
